import{_ as t,o,c as a,ag as r}from"./chunks/framework.YaIgwL5o.js";const p=JSON.parse('{"title":"Feature Overview","description":"","frontmatter":{},"headers":[],"relativePath":"features/overview.md","filePath":"features/overview.md"}'),i={name:"features/overview.md"};function s(l,e,n,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="feature-overview" tabindex="-1">Feature Overview <a class="header-anchor" href="#feature-overview" aria-label="Permalink to &quot;Feature Overview&quot;">​</a></h1><p>A high-level tour of everything Slides Editor can do.</p><h2 id="editing" tabindex="-1">Editing <a class="header-anchor" href="#editing" aria-label="Permalink to &quot;Editing&quot;">​</a></h2><p>Slides Editor is built around a drag-and-drop canvas. Every element on a slide — text boxes, images, shapes, code blocks, LaTeX blocks, charts — can be:</p><ul><li><strong>Clicked to select</strong> and dragged to reposition</li><li><strong>Resized</strong> by dragging corner or edge handles (hold <code>Shift</code> to lock aspect ratio)</li><li><strong>Rotated</strong> by dragging the rotation handle above the element (hold <code>Shift</code> to snap to 15°)</li><li><strong>Layered</strong> using bring-forward / send-backward controls</li><li><strong>Aligned</strong> with the built-in alignment toolbar</li></ul><p>An undo/redo stack tracks every change (<code>Ctrl+Z</code> / <code>Ctrl+Y</code>).</p><h2 id="element-types" tabindex="-1">Element Types <a class="header-anchor" href="#element-types" aria-label="Permalink to &quot;Element Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Description</th></tr></thead><tbody><tr><td>Text box</td><td>Rich text with TipTap — headings, bold/italic/underline, lists, tables, inline math</td></tr><tr><td>Image</td><td>Upload or paste images; resize and reposition freely</td></tr><tr><td>Shape</td><td>Rectangle, circle, arrow, line — filled or outlined, any color</td></tr><tr><td>Code block</td><td>Syntax-highlighted code via highlight.js; supports 100+ languages</td></tr><tr><td>LaTeX block</td><td>Display math and TikZ diagrams with live split-pane preview</td></tr><tr><td>Chart</td><td>Bar, line, and scatter charts powered by Chart.js</td></tr><tr><td>Embed</td><td>Iframe embeds for web content</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To insert a new element, right-click on the slide canvas or use the <strong>Insert</strong> toolbar at the top of the editor.</p></div><h2 id="slides" tabindex="-1">Slides <a class="header-anchor" href="#slides" aria-label="Permalink to &quot;Slides&quot;">​</a></h2><ul><li><strong>Add, duplicate, delete</strong> slides from the panel on the left</li><li><strong>Reorder</strong> by drag-and-drop in the panel</li><li><strong>Vertical stacks</strong> — nest slides below a parent for reveal.js-style vertical navigation</li><li><strong>Per-slide background</strong> — solid color, gradient, or image</li><li><strong>Speaker notes</strong> — each slide has an optional notes pane visible in presenter mode</li><li><strong>Slide transitions</strong> — choose from reveal.js transitions (fade, slide, zoom, convex, concave, none)</li></ul><h2 id="footer-system" tabindex="-1">Footer System <a class="header-anchor" href="#footer-system" aria-label="Permalink to &quot;Footer System&quot;">​</a></h2><p>The footer system lets you define a <strong>section sequence</strong> shown at the bottom of every slide — useful for academic talks.</p><ul><li>Define named sections (e.g., Introduction, Methods, Results, Discussion)</li><li>Each section&#39;s progress dot highlights as you advance through slides</li><li>Customizable font, size, and color to match your theme</li></ul><h2 id="themes-templates" tabindex="-1">Themes &amp; Templates <a class="header-anchor" href="#themes-templates" aria-label="Permalink to &quot;Themes &amp; Templates&quot;">​</a></h2><ul><li><strong>11 built-in reveal.js themes</strong>: Black, White, League, Beige, Sky, Night, Serif, Simple, Solarized, Moon, Dracula</li><li><strong>6 design presets</strong>: Academic, Minimal, Dark Tech, Warm, High Contrast, Pastel</li><li><strong>Custom templates</strong>: Save any slide as a reusable template to re-use across presentations</li><li><strong>Per-slide overrides</strong>: Change the background image or color on individual slides without affecting the rest of the deck</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Design presets apply a coordinated color palette, font stack, and default element styles all at once — great for getting a polished look quickly.</p></div><h2 id="export-sharing" tabindex="-1">Export &amp; Sharing <a class="header-anchor" href="#export-sharing" aria-label="Permalink to &quot;Export &amp; Sharing&quot;">​</a></h2><ul><li><strong>Standalone HTML</strong> — a single <code>.html</code> file that plays reveal.js from CDN</li><li><strong>Offline HTML</strong> — all CDN assets inlined; works without internet access</li><li><strong>PDF</strong> — print-ready via browser print dialog with all fragments expanded</li><li><strong>PPTX</strong> — PowerPoint-compatible export</li><li><strong>Shareable link</strong> — generate a URL to share a read-only or editable view</li><li><strong>GitHub push</strong> — commit your presentation directly to a GitHub repository</li></ul><p>See <a href="/revealjs_gui/features/export.html">Export &amp; Sharing</a> for details.</p><h2 id="cloud-sync" tabindex="-1">Cloud Sync <a class="header-anchor" href="#cloud-sync" aria-label="Permalink to &quot;Cloud Sync&quot;">​</a></h2><p>Sync your presentations folder to a remote storage provider using <a href="https://rclone.org/" target="_blank" rel="noreferrer">rclone</a>:</p><ul><li><strong>Proton Drive</strong> — first-class support with guided setup</li><li><strong>S3-compatible</strong> — AWS S3, Backblaze B2, Cloudflare R2, MinIO</li><li><strong>Google Drive, Dropbox</strong> — via standard rclone remotes</li><li>Manual sync or automatic background sync at a configurable interval</li></ul><h2 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h2><p>Slides Editor maintains a local version history for each presentation:</p><ul><li>Automatic snapshots on save</li><li>Browse and restore any previous version</li><li>Diff view shows which slides changed between versions</li></ul>',26)])])}const u=t(i,[["render",s]]);export{p as __pageData,u as default};
